DO $$
DECLARE
  v_tenant_id UUID;
  v_sop_id    UUID;
BEGIN
  SELECT id INTO v_tenant_id FROM tenants LIMIT 1;
  IF v_tenant_id IS NULL THEN
    RAISE NOTICE 'Nenhum tenant encontrado. Abortando seed.';
