  INSERT INTO knowledge_sop_steps (sop_id, step_number, title, content, step_type, order_index) VALUES
    (v_sop_id, 1, 'Objetivo', E'Definir o protocolo de ação para situações de crise no relacionamento com clientes: insatisfação grave, atraso crítico, ameaça de cancelamento ou ruptura de contrato.\n\n**Princípio central:** Em uma crise, a percepção do cliente sobre COMO você age é mais importante que o problema em si. Uma crise bem gerida pode fortalecer o relacionamento mais do que um projeto sem problemas.', 'step', 0),
    (v_sop_id, 2, 'Escopo', E'**Quem executa:** Atendimento (ponto de contato primário) + Ruy ou Marco (obrigatório em crises nível 2 e 3)\n**Quando se aplica:**\n- Cliente expressou insatisfação grave (NPS < 6, reclamação formal, mensagem hostil)\n- Atraso comprometeu evento ou prazo crítico do cliente\n- Cliente sinalizou cancelamento ou acionamento jurídico\n- Erro da TBO com impacto financeiro ou reputacional\n**Não se aplica:** Feedbacks negativos em revisão normal (ver SOP tbo-atd-006)', 'step', 1),
    (v_sop_id, 3, 'RACI', E'| Atividade | Responsável | Aprovador | Consultado | Informado |\n|---|---|---|---|---|\n| Detecção e classificação da crise | Atendimento | — | — | Marco + Ruy (imediato) |\n| Definição do plano de ação | Ruy | Marco | Atendimento + Líder de BU | — |\n| Comunicação inicial com o cliente | Atendimento | Ruy | — | Marco |\n| Implementação técnica da solução | Líder de BU | Ruy | — | Atendimento |\n| Reunião de reconciliação | Ruy ou Marco | — | Atendimento | — |\n| Post-mortem e melhorias | Head de Ops | Marco | Líder de BU | Todos |', 'step', 2),
    (v_sop_id, 4, 'Pré-requisitos', E'- [ ] Acesso ao histórico completo do cliente no TBO OS\n- [ ] Contato direto de Ruy e Marco disponível (WhatsApp)\n- [ ] Contrato e escopo do projeto acessível\n- [ ] Registro do incidente iniciado antes de comunicar ao cliente\n\n**IMPORTANTE:** Não comunicar ao cliente sem ter os fatos organizados e Ruy/Marco alinhados.', 'step', 3),
    (v_sop_id, 5, 'Procedimento', E'**FASE 1 — Contenção (primeiras 2h):**\n1. Classificar severidade:\n   - **Nível 1 (Amarelo):** Insatisfação expressa, sem ameaça de cancelamento\n   - **Nível 2 (Laranja):** Reclamação formal, prazo comprometido\n   - **Nível 3 (Vermelho):** Ameaça de cancelamento, jurídico, post público\n2. Notificar Marco e Ruy imediatamente (WhatsApp)\n3. Realizar war room (30 min): Ruy + Marco + Atendimento + Líder de BU\n4. Definir o que aconteceu, responsabilidade e o que oferecer ao cliente\n\n**FASE 2 — Comunicação inicial (primeiras 4h):**\n1. Primeiro contato: **ligação telefônica** (nível 2/3: Ruy liga; nível 1: Atendimento)\n2. Abertura: "Soube o que aconteceu e queria falar pessoalmente"\n3. Mostrar que entende o impacto — sem desculpas genéricas\n4. Apresentar plano de ação com prazos concretos\n5. Confirmar por e-mail no mesmo dia (ver Template Anexo)\n\n**FASE 3 — Resolução:**\n- Nível 1: ≤ 5 dias úteis\n- Nível 2: plano em 48h, entrega em 5 dias\n- Nível 3: plano em 24h, entrega em 3 dias\n- Atualizar o cliente a cada 24h durante a resolução\n- QA reforçado antes de entregar\n\n**FASE 4 — Reconciliação:**\n1. Reunião presencial de reconciliação\n2. Post-mortem interno documentado no TBO OS\n3. Oferecer algo de valor ao cliente\n4. Monitoramento pós-crise por 30 dias (check-in quinzenal + NPS)', 'step', 4),
    (v_sop_id, 6, 'Checklist de Validação', E'**Contenção:**\n- [ ] Crise classificada (nível 1/2/3)\n- [ ] Marco e Ruy notificados imediatamente\n- [ ] War room realizado antes de contatar o cliente\n\n**Comunicação:**\n- [ ] Primeiro contato por telefone (nível 2 ou 3)\n- [ ] Plano de ação concreto apresentado\n- [ ] E-mail formal enviado no mesmo dia\n\n**Resolução:**\n- [ ] Solução entregue dentro do prazo prometido\n- [ ] QA reforçado antes da entrega\n\n**Reconciliação:**\n- [ ] Reunião de reconciliação realizada\n- [ ] Post-mortem documentado no TBO OS\n- [ ] NPS aplicado 30 dias após resolução\n- [ ] Cliente saiu do status "crise" no TBO OS', 'checkpoint', 5),
    (v_sop_id, 7, 'Ferramentas e Recursos', E'- **TBO OS**: campo "status de relacionamento" (normal / atenção / crise) + "lições aprendidas"\n- **WhatsApp**: comunicação de emergência com Marco e Ruy\n- **Google Meet**: war room e reunião de reconciliação\n- **E-mail**: documentação formal de plano de ação\n- **Template de e-mail de crise**: ver Template Anexo\n- **NPS pós-resolução**: Google Forms — template em `Drive > Templates > Atendimento`', 'tip', 6),
    (v_sop_id, 8, 'SLAs e Métricas', E'| Situação | SLA |\n|---|---|\n| Notificar Marco+Ruy após detectar | ≤ 30 min |\n| War room interno | ≤ 2h após detecção |\n| Primeiro contato com cliente (nível 1) | ≤ 4h |\n| Primeiro contato com cliente (nível 2/3) | ≤ 2h |\n| Plano de ação enviado por escrito | ≤ 4h após primeiro contato |\n| NPS pós-resolução | 30 dias após encerramento |\n| Taxa de retenção de clientes após crise | Meta: ≥ 85% |', 'note', 7),
    (v_sop_id, 9, 'Troubleshooting', E'**Cliente vai a público (redes sociais, grupos do setor):**\n→ Acionar Marco imediatamente — resposta pública é decisão estratégica\n→ Resposta pública rápida e empática: "Lamento saber disso. Vou contatar você pessoalmente."\n→ Não travar debate público — resolver em privado\n\n**Cliente ameaça acionar advogado:**\n→ Acionar Marco + assessoria jurídica da TBO imediatamente\n→ Toda comunicação por e-mail (documentada) a partir desse ponto\n→ Não fazer promessas financeiras sem aprovação de Marco\n\n**Crise causada por erro do cliente (mas ele não admite):**\n→ Não confrontar com provas imediatamente\n→ Com Ruy/Marco: decidir se vale a briga ou melhor absorver\n→ Registrar internamente para referência futura', 'warning', 8),
    (v_sop_id, 10, 'Template Anexo', E'**E-mail de Plano de Ação**\n```\nAssunto: [Projeto X] — Nossa resposta e próximos passos\n\nOlá [Nome],\n\nFalamos hoje e quero registrar o que discutimos.\n\nO que aconteceu: [Descrição breve e objetiva]\nNossa responsabilidade: [O que é erro nosso — assumir claramente]\n\nO que vamos fazer:\n1. [Ação concreta] — Prazo: [data]\n2. [Ação concreta] — Prazo: [data]\n\nSeu contato direto:\n[Nome] | [telefone] | [e-mail]\n\nPedimos desculpas pelo impacto causado.\n[Assinatura]\n```\n\n**Escala de Severidade (referência rápida)**\n```\n🟡 NÍVEL 1 — AMARELO\nSintoma: Insatisfação expressa\nAção: Atendimento responde em 4h\n\n🟠 NÍVEL 2 — LARANJA\nSintoma: Reclamação formal, prazo comprometido\nAção: Ruy liga em 2h, plano em 48h\n\n🔴 NÍVEL 3 — VERMELHO\nSintoma: Cancelamento, jurídico, post público\nAção: Marco + Ruy em 30 min, war room imediato\n```', 'tip', 9);

  -- ══════════════════════════════════════════════════════════════════════════
  -- SOP 3: Relacionamentos — Co-criação e Workshops com Clientes
  -- ══════════════════════════════════════════════════════════════════════════
  INSERT INTO knowledge_sops (
    tenant_id, title, slug, bu, category, description, content, content_html,
    status, priority, tags, order_index, version
  ) VALUES (
    v_tenant_id,
    'Co-criação e Workshops com Clientes',
    'tbo-rel-010-co-criacao-workshops-clientes',
    'relacionamentos',
    'processo',
    'Processo para organizar e facilitar workshops de co-criação com clientes — desde a concepção do formato até o follow-up com entregáveis. Cobre dinâmicas de ideação, facilitação presencial e remota, e documentação de outputs que viram briefings ou decisões de projeto.',
    E'## Co-criação e Workshops com Clientes\n\n### 1. Objetivo\nPadronizar o processo de organização e facilitação de workshops de co-criação com clientes, transformando reuniões estratégicas em sessões produtivas que geram decisões claras, briefings alinhados e relacionamentos mais próximos. Um workshop bem facilitado é um diferencial competitivo: o cliente sente que co-construiu a solução, aumentando o compromisso com o resultado.\n\n### 2. Escopo\n**Quem executa:** Marco (facilita ou co-facilita) + Atendimento (logística e documentação) + Líder de BU relevante\n**Quando se aplica:**\n- Início de projetos complexos ou de longo prazo (identidade visual, campanha, estratégia de marca)\n- Alinhamento de visão entre stakeholders do cliente (múltiplos decisores)\n- Quando briefing está vago ou há múltiplas direções possíveis\n- Imersões de marca ou posicionamento\n**Formatos cobertos:** Presencial (escritório TBO ou cliente), remoto (Miro + Google Meet), híbrido\n**Duração típica:** 2-4 horas (half-day) ou 6-8 horas (full-day)\n\n### 3. RACI\n\n| Atividade | Responsável | Aprovador | Consultado | Informado |\n|---|---|---|---|---|\n| Definição do objetivo e formato do workshop | Marco | Ruy | Atendimento + Líder de BU | Cliente |\n| Logística e convites | Atendimento | Marco | — | — |\n| Preparação do material (roteiro, dinâmicas) | Marco | — | Líder de BU | — |\n| Facilitação | Marco (principal) | — | Líder de BU | — |\n| Documentação em tempo real | Atendimento | — | — | — |\n| Síntese e outputs pós-workshop | Atendimento | Marco | Líder de BU | — |\n| Follow-up com o cliente | Atendimento | Marco | — | Ruy |\n\n### 4. Pré-requisitos\n\n- [ ] Objetivo claro do workshop definido (o que precisa estar decidido ao final?)\n- [ ] Participantes do cliente identificados (quem são os decisores? quem precisa estar presente?)\n- [ ] Data e local (ou link) confirmados com pelo menos 1 semana de antecedência\n- [ ] Material de referência preparado (benchmark, referências visuais, dados relevantes)\n- [ ] Espaço físico preparado se presencial: paredes limpas, post-its, canetas, projetor\n- [ ] Miro Board preparado se remoto: template com áreas de cada dinâmica\n- [ ] Roteiro do workshop finalizado com timing por dinâmica\n\n### 5. Procedimento\n\n**5.1 Pré-workshop (até 3 dias antes)**\n\n1. **Definição do objetivo** com Marco e Líder de BU:\n   - Qual pergunta precisa estar respondida ao final do workshop?\n   - Qual o entregável esperado (briefing, moodboard, direção aprovada, roadmap?)\n   - Qual o nível de alinhamento atual do cliente sobre o projeto?\n\n2. **Seleção das dinâmicas** (adequar à duração e objetivo):\n   - **Definição de território de marca**: "Como/Para quem/Por que" (golden circle adaptado)\n   - **Moodboard colaborativo**: cada participante traz 3-5 referências que "parecem" e "não parecem" com a marca\n   - **Jornada do usuário/comprador**: mapear experiência do cliente final do empreendimento\n   - **Priorização com dot voting**: para decidir entre direções\n   - **How Might We (HMW)**: para gerar soluções criativas\n\n3. **Preparar o roteiro com timing:**\n   ```\n   00:00 - 00:15  Abertura e contexto (Marco)\n   00:15 - 00:45  Dinâmica 1: [nome] (Marco facilita)\n   00:45 - 01:30  Dinâmica 2: [nome]\n   01:30 - 01:45  Coffee break\n   01:45 - 02:30  Dinâmica 3: [nome]\n   02:30 - 03:00  Síntese e próximos passos (Atendimento documenta)\n   ```\n\n4. **Enviar material preparatório ao cliente** (1-2 dias antes):\n   - Agenda e objetivo do workshop\n   - Qualquer "dever de casa" (ex: trazer referências, responder 3 perguntas)\n   - Logística prática (endereço, link, estacionamento)\n\n**5.2 Durante o workshop**\n\n1. **Abertura (Marco conduz):**\n   - Contextualizar: por que estamos aqui e o que vamos construir juntos\n   - Apresentar a agenda e o entregável esperado\n   - "Regras do jogo": sem julgamentos, todas as ideias são válidas, foco no usuário final\n   - Quebra-gelo rápido (opcional para grupos que não se conhecem)\n\n2. **Facilitação das dinâmicas:**\n   - Marco facilita; Atendimento documenta (fotos, notas, board Miro)\n   - Manter o tempo — Marco avisa 5 min antes de fechar cada dinâmica\n   - Capturar as "frases-chave" do cliente literalmente (serão usadas no briefing)\n   - Se debater muito: usar dot voting para convergir\n   - Se silêncio: estimular com perguntas diretas ("E você, [nome], o que acha?")\n\n3. **Síntese ao final:**\n   - Marco sintetiza em voz alta os principais outputs de cada dinâmica\n   - Confirmar com o grupo: "Isso representa o que construímos juntos?"\n   - Definir próximos passos claros: "Com isso, vamos criar [X] e retornar em [Y] dias"\n\n**5.3 Pós-workshop (até 48h depois)**\n\n1. Atendimento estrutura a síntese:\n   - Decisões tomadas (com contexto)\n   - Direções descartadas (com motivo)\n   - Frases-chave do cliente\n   - Próximos passos com responsáveis e prazos\n\n2. Marco revisa a síntese antes de enviar\n\n3. Enviar ao cliente em até 48h:\n   - Documento de síntese (PDF ou Notion)\n   - Fotos do board / export do Miro\n   - Próximos passos confirmados\n\n4. Usar os outputs como insumo direto para o briefing criativo (SOP tbo-atd-005)\n\n### 6. Checklist de Validação\n\n**Antes:**\n- [ ] Objetivo do workshop definido (pergunta que precisa ser respondida)\n- [ ] Participantes confirmados (com decisores presentes)\n- [ ] Roteiro com timing definido\n- [ ] Material preparatório enviado ao cliente\n- [ ] Espaço / Miro Board preparado\n\n**Durante:**\n- [ ] Outputs de cada dinâmica documentados (fotos, notas, board)\n- [ ] Frases-chave do cliente registradas literalmente\n- [ ] Síntese verbal feita no final e confirmada com o grupo\n- [ ] Próximos passos definidos na sala\n\n**Após:**\n- [ ] Síntese estruturada (revisada por Marco)\n- [ ] Documento enviado ao cliente em até 48h\n- [ ] Outputs incorporados ao briefing do projeto\n- [ ] Ticket no TBO OS atualizado com decisões do workshop\n\n### 7. Ferramentas e Recursos\n\n- **Facilitação remota**: Miro (templates em `Drive > Templates > Relacionamentos > Workshops`)\n- **Videoconferência**: Google Meet (gravar sempre em workshops remotos)\n- **Documentação**: Notion ou Google Docs para síntese\n- **Material físico**: post-its (3 cores), canetas piloto, papel A3, câmera para fotos\n- **Timer**: Cuckoo.team (público, todos veem) para gestão de tempo visível\n- **Dot voting online**: ferramenta nativa do Miro\n\n### 8. SLAs e Métricas\n\n| Etapa | SLA |\n|---|---|\n| Envio de material preparatório ao cliente | ≤ 2 dias antes do workshop |\n| Envio da síntese pós-workshop | ≤ 48h após o workshop |\n| Duração máxima sem pausa | 90 min (coffee break obrigatório) |\n| Satisfação do cliente (avaliação pós-workshop) | Meta: ≥ 4.5/5 |\n| Taxa de workshops que geram briefing aprovado | Meta: ≥ 80% |\n\n### 9. Troubleshooting\n\n**Participante dominante monopoliza o workshop:**\n→ Usar técnica "cada um fala por vez" (round robin) nas dinâmicas\n→ Intervenção gentil: "Ótimo ponto. Vamos ouvir a perspectiva dos outros antes de aprofundar?"\n\n**Workshop deriva e não converge:**\n→ Usar dot voting para forçar priorização\n→ Marco intervém: "Precisamos chegar em uma decisão até [horário]. Vamos votar nas 3 opções mais promissoras."\n\n**Cliente sem energia / baixo engajamento:**\n→ Pausa de 10 min (café, movimento físico)\n→ Mudar de dinâmica — se estava em silêncio, ir para algo mais ativo\n→ Se remoto: câmeras ligadas são obrigatórias, atividades com participação ativa (escrever no Miro)\n\n**Decisor ausente na hora H:**\n→ Não tomar decisões que dependam dele sem sua presença\n→ Documentar outputs como "direções provisórias — pendente validação de [nome]"\n\n### 10. Template Anexo\n\n**Roteiro de Workshop (modelo 3h)**\n```\nWORKSHOP: [PROJETO / EMPREENDIMENTO]\nData: ___  Local/Link: ___\nParticipantes TBO: Marco, [Atendimento], [Líder de BU]\nParticipantes Cliente: ___\n\nOBJETIVO: Ao final deste workshop, teremos definido: ___\n\nAGENDA:\n00:00-00:15  Abertura e contexto\n00:15-00:45  Dinâmica 1: [nome + objetivo]\n00:45-01:30  Dinâmica 2: [nome + objetivo]\n01:30-01:45  Coffee break\n01:45-02:30  Dinâmica 3: [nome + objetivo]\n02:30-02:50  Síntese colaborativa\n02:50-03:00  Próximos passos\n\nENTREGÁVEL ESPERADO:\n[ ] Briefing criativo validado\n[ ] Moodboard de direção aprovada\n[ ] Decisão de posicionamento\n[ ] Outro: ___\n```\n\n**Síntese Pós-Workshop (template)**\n```\nSÍNTESE DO WORKSHOP — [PROJETO]\nData: ___  Participantes: ___\n\nDECISÕES TOMADAS:\n1. [Decisão] — Contexto: [motivo]\n2. [Decisão] — Contexto: [motivo]\n\nDIREÇÕES DESCARTADAS:\n- [Direção] — Motivo: ___\n\nFRASES-CHAVE DO CLIENTE:\n"[transcrição literal]"\n"[transcrição literal]"\n\nPRÓXIMOS PASSOS:\n| Ação | Responsável | Prazo |\n|---|---|---|\n| [Ação] | TBO | [data] |\n| [Ação] | [Cliente] | [data] |\n```',
    '',
    'published',
    'medium',
    ARRAY['relacionamentos', 'workshop', 'co-criacao', 'briefing', 'cliente', 'facilitacao', 'ideacao'],
    10,
    1
  )
